const input = $input.first().json || {};
const body = input.body || {};
const query = input.query || {};
const params = { ...body, ...query };

const decisionRaw = String(params.decision || params.action || '').trim().toLowerCase();
const approved = ['approve', 'approved', 'send', 'yes'].includes(decisionRaw);
const rejected = ['reject', 'rejected', 'deny', 'no'].includes(decisionRaw);

if (!approved && !rejected) {
  throw new Error('decision is required and must be approve or reject');
}

const approvalId = params.approval_id || params.approvalId || null;
const token = params.token || params.approval_token || null;

if (!approvalId) {
  throw new Error('approval_id is required');
}
if (!token) {
  throw new Error('approval token is required');
}

return [{
  json: {
    decision: approved ? 'approved' : 'rejected',
    approved,
    rejected,
    approval_id: approvalId,
    token,
    reviewer: params.reviewer || params.approver || 'slack_button',
    notes: params.notes || params.reason || '',
    decided_at: new Date().toISOString()
  }
}];

const request = $('Validate Request').first().json;
const approval = $input.first().json || {};

if (!approval.id) {
  throw new Error('approval not found');
}

let payload = approval.request_payload || {};
if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (e) {
    throw new Error('approval request_payload is not valid JSON');
  }
}

const expectedToken = payload.approval_token || payload.token;
if (!expectedToken || expectedToken !== request.token) {
  throw new Error('invalid approval token');
}

if (approval.status && approval.status !== 'pending') {
  throw new Error(`approval is already ${approval.status}`);
}

if (approval.expires_at && new Date(approval.expires_at).getTime() < Date.now()) {
  throw new Error('approval has expired');
}

const draftId = payload.draft_id || payload.draftId || payload.gmail_draft_id;
if (request.approved && !draftId) {
  throw new Error('approval payload is missing draft_id');
}

return [{
  json: {
    ...request,
    draft_id: draftId || null,
    event_id: payload.event_id || null,
    recipient: payload.to || payload.recipient || '',
    subject: payload.subject || '',
    thread_id: payload.thread_id || payload.threadId || null,
    draft_preview: payload.draft_preview || '',
    approval_payload: payload
  }
}];

const decision = $('Validate Approval Token').first().json;
const sent = $input.first().json || {};

return [{
  json: {
    ...decision,
    sent_message_id: sent.id || sent.messageId || null,
    gmail_result: sent,
    final_status: 'sent'
  }
}];

const decision = $('Validate Approval Token').first().json;

return [{
  json: {
    ...decision,
    sent_message_id: null,
    gmail_result: null,
    final_status: 'rejected'
  }
}];

let result;
try {
  result = $('Build Approved Result').first().json;
} catch (e) {
  result = $('Build Rejected Result').first().json;
}

const statusLine = result.approved
  ? `Approved by ${result.reviewer}. Gmail draft was sent.`
  : `Rejected by ${result.reviewer}. Gmail draft was not sent.`;

return [{
  json: {
    ...result,
    channel: '#email-routing',
    message: `*Email Approval Decision*\n*Status:* ${result.final_status}\n*Subject:* ${result.subject || '(not provided)'}\n*To:* ${result.recipient || '(not provided)'}\n*Draft ID:* ${result.draft_id || '(none)'}\n*Reviewer:* ${result.reviewer}\n*Notes:* ${result.notes || '(none)'}\n${statusLine}`
  }
}];

const result = $('Prepare Slack Notification').first().json;

return [{
  json: {
    workflow_name: 'EMAIL__ApproveAndSend',
    execution_id: $execution.id,
    log_type: 'action',
    action: result.approved ? 'draft_approved_and_sent' : 'draft_rejected',
    input_payload: {
      approval_id: result.approval_id,
      event_id: result.event_id,
      draft_id: result.draft_id,
      subject: result.subject,
      recipient: result.recipient,
      reviewer: result.reviewer,
      notes: result.notes
    },
    output_payload: {
      final_status: result.final_status,
      sent_message_id: result.sent_message_id
    },
    status: 'success'
  }
}];

const result = $('Prepare Slack Notification').first().json;
const title = result.approved ? 'Email draft sent' : 'Email draft rejected';
const detail = result.approved
  ? 'The approved Gmail draft has been sent.'
  : 'The Gmail draft was rejected and was not sent.';

return [{
  json: {
    success: true,
    title,
    detail,
    workflow: 'EMAIL__ApproveAndSend',
    decision: result.decision,
    final_status: result.final_status,
    approval_id: result.approval_id,
    event_id: result.event_id,
    draft_id: result.draft_id,
    sent_message_id: result.sent_message_id,
    reviewer: result.reviewer,
    decided_at: result.decided_at
  }
}];
